function uniqueValues(values) {
  return [...new Set(values.filter(Boolean))];
}

function seededRandom(seed) {
  let value = seed % 2147483647;
  if (value <= 0) value += 2147483646;
  return () => {
    value = (value * 16807) % 2147483647;
    return (value - 1) / 2147483646;
  };
}

function shuffleWithSeed(values, seed) {
  const next = [...values];
  const random = seededRandom(seed);
  for (let i = next.length - 1; i > 0; i -= 1) {
    const j = Math.floor(random() * (i + 1));
    [next[i], next[j]] = [next[j], next[i]];
  }
  return next;
}

function buildOptions(correct, distractors, seed) {
  const options = uniqueValues([correct, ...distractors.filter((item) => item !== correct)]).slice(0, 4);
  return options.length === 4 ? shuffleWithSeed(options, seed) : null;
}

function addQuestion(questions, prompt, correctAnswer, distractors, difficulty, seed) {
  const options = buildOptions(correctAnswer, distractors, seed);
  if (!prompt || !correctAnswer || !options) return;
  questions.push({ prompt, correctAnswer, options, difficulty });
}

function createSkillBank(config, stateDetails) {
  const { fundamentals, practices, advanced } = config;
  const questions = [];
  const fundamentalMeanings = fundamentals.map((item) => item.meaning);
  const fundamentalUses = fundamentals.map((item) => item.use);
  const fundamentalImpacts = fundamentals.map((item) => item.impact);
  const fundamentalRisks = fundamentals.map((item) => item.risk);

  fundamentals.forEach((item, index) => {
    addQuestion(
      questions,
      `In ${stateDetails.title}, what does "${item.term}" mainly refer to?`,
      item.meaning,
      fundamentalMeanings.filter((value) => value !== item.meaning),
      'easy',
      101 + index
    );
    addQuestion(
      questions,
      `Which task best shows hands-on understanding of "${item.term}"?`,
      item.use,
      fundamentalUses.filter((value) => value !== item.use),
      'easy',
      201 + index
    );
    addQuestion(
      questions,
      `Why do strong candidates need "${item.term}" for ${stateDetails.title}?`,
      item.impact,
      fundamentalImpacts.filter((value) => value !== item.impact),
      'easy',
      301 + index
    );
    addQuestion(
      questions,
      `Which problem most often appears when "${item.term}" is weak?`,
      item.risk,
      fundamentalRisks.filter((value) => value !== item.risk),
      'easy',
      401 + index
    );
  });

  const practiceBest = practices.map((item) => item.best);
  const practiceReason = practices.map((item) => item.reason);
  const practiceMetric = practices.map((item) => item.metric);
  const practiceAntiPattern = practices.map((item) => item.antiPattern);
  const practiceNextStep = practices.map((item) => item.nextStep);

  practices.forEach((item, index) => {
    addQuestion(
      questions,
      item.scenario,
      item.best,
      practiceBest.filter((value) => value !== item.best),
      'medium',
      501 + index
    );
    addQuestion(
      questions,
      `Why is that the best approach in this case?`,
      item.reason,
      practiceReason.filter((value) => value !== item.reason),
      'medium',
      601 + index
    );
    addQuestion(
      questions,
      `Which check or metric should you review first?`,
      item.metric,
      practiceMetric.filter((value) => value !== item.metric),
      'medium',
      701 + index
    );
    addQuestion(
      questions,
      `Which mistake should be avoided in this scenario?`,
      item.antiPattern,
      practiceAntiPattern.filter((value) => value !== item.antiPattern),
      'medium',
      801 + index
    );
    addQuestion(
      questions,
      `After the first fix, what is the strongest next step?`,
      item.nextStep,
      practiceNextStep.filter((value) => value !== item.nextStep),
      'medium',
      901 + index
    );
  });

  const advancedAnswers = advanced.map((item) => item.answer);
  const advancedReasons = advanced.map((item) => item.reason);
  const advancedTradeoffs = advanced.map((item) => item.tradeoff);
  const advancedAntiPatterns = advanced.map((item) => item.antiPattern);
  const advancedFocus = advanced.map((item) => item.focus);

  advanced.forEach((item, index) => {
    addQuestion(
      questions,
      item.prompt,
      item.answer,
      advancedAnswers.filter((value) => value !== item.answer),
      'hard',
      1001 + index
    );
    addQuestion(
      questions,
      `Why is that the strongest answer?`,
      item.reason,
      advancedReasons.filter((value) => value !== item.reason),
      'hard',
      1101 + index
    );
    addQuestion(
      questions,
      `Which tradeoff comes with that decision?`,
      item.tradeoff,
      advancedTradeoffs.filter((value) => value !== item.tradeoff),
      'hard',
      1201 + index
    );
    addQuestion(
      questions,
      `Which failure pattern is this decision mainly preventing?`,
      item.antiPattern,
      advancedAntiPatterns.filter((value) => value !== item.antiPattern),
      'hard',
      1301 + index
    );
    addQuestion(
      questions,
      `What should remain the primary focus while applying it?`,
      item.focus,
      advancedFocus.filter((value) => value !== item.focus),
      'hard',
      1401 + index
    );
  });

  return questions.slice(0, 100);
}

