export function buildAssessmentQuestionBank(stateDetails) {
  const config = stateDetails?.state_id ? SKILL_BANKS[stateDetails.state_id] : null;
  return config ? createSkillBank(config, stateDetails) : [];
}

export function getSkillQuestionBankConfig(stateId) {
  return stateId ? SKILL_BANKS[stateId] || null : null;
}

export function buildAssessmentQuestionsFromBank(stateDetails, seed = 1) {
  const bank = buildAssessmentQuestionBank(stateDetails);
  if (!bank.length) return [];

  const easy = shuffleWithSeed(bank.filter((question) => question.difficulty === 'easy'), seed + 11).slice(0, 9);
  const medium = shuffleWithSeed(bank.filter((question) => question.difficulty === 'medium'), seed + 22).slice(0, 8);
  const hard = shuffleWithSeed(bank.filter((question) => question.difficulty === 'hard'), seed + 33).slice(0, 8);

  return shuffleWithSeed([...easy, ...medium, ...hard], seed + 44).map((question, index) => ({
    id: `${stateDetails.state_id}-${question.difficulty}-${index + 1}`,
    index: index + 1,
    ...question,
  }));
}
